The transverse displacement $y(x,t)$ of a string satisfies the wave equation:
\begin{equation*}
\frac{\partial^2 y}{\partial x^2} = \frac{1}{v^2} \frac{\partial^2 y}{\partial t^2}
\end{equation*}
where $v = \sqrt{\frac{T}{\eta}}$ is the wave speed, $T$ is the tension, and $\eta$ is the linear density.

For normal modes of oscillation, we assume a separable solution of the form $y(x,t) = Y(x) \cos(\omega t + \phi)$. Substituting this into the wave equation leads to the Helmholtz equation for $Y(x)$:
\begin{equation*}
\frac{d^2 Y}{dx^2} + k^2 Y = 0
\end{equation*}
where $k = \frac{\omega}{v}$ is the wave number.

The general solution for $Y(x)$ is:
\begin{equation*}
Y(x) = A \cos(kx) + B \sin(kx)
\end{equation*}

Now, we apply the boundary conditions:
\begin{enumerate}
    \item \textbf{Fixed end at $x=0$:}
    The string is fixed at $x=0$, so the displacement must be zero: $y(0,t) = 0$. This implies $Y(0) = 0$.
    \begin{align*} A \cos(0) + B \sin(0) &= 0 \\ A &= 0 \end{align*}
    So, the solution for $Y(x)$ simplifies to $Y(x) = B \sin(kx)$.

    \item \textbf{Massless ring at $x=l$:}
    The string terminates at a massless ring at $x=l$ that can slide freely without friction on a vertical rod. Since the ring is massless, the net force on it must be zero. As it slides vertically, the only vertical force acting on it is the vertical component of the tension from the string. For small oscillations, the vertical component of the tension exerted by the string on the ring is $-T \left(\frac{\partial y}{\partial x}\right)_{x=l}$. For the ring to be in equilibrium (or oscillate without external vertical forces), this force must be zero:
    \begin{equation*}
    -T \left(\frac{\partial y}{\partial x}\right)_{x=l} = 0
    \end{equation*}
    Since $T \neq 0$, we must have $\left(\frac{\partial y}{\partial x}\right)_{x=l} = 0$. This implies $Y'(l) = 0$.
    Differentiating $Y(x) = B \sin(kx)$ with respect to $x$, we get $Y'(x) = Bk \cos(kx)$.
    Setting $Y'(l) = 0$:
    \begin{equation*}
    Bk \cos(kl) = 0
    \end{equation*}
    Since we are looking for non-trivial oscillations, $B \neq 0$ and $k \neq 0$. Therefore, we must have:
    \begin{equation*}
    \cos(kl) = 0
    \end{equation*}
    This condition is satisfied when $kl$ is an odd multiple of $\frac{\pi}{2}$:
    \begin{equation*}
    kl = \left(n + \frac{1}{2}\right)\pi, \quad \text{for } n = 0, 1, 2, \dots
    \end{equation*}
\end{enumerate}
Thus, the allowed wave numbers $k_n$ are:
\begin{equation*}
k_n = \frac{\left(n + \frac{1}{2}\right)\pi}{l}
\end{equation*}
The angular frequencies $\omega_n$ of the normal modes are related by $\omega_n = k_n v$:
\begin{equation*}
\omega_n = \frac{\left(n + \frac{1}{2}\right)\pi}{l} \sqrt{\frac{T}{\eta}}
\end{equation*}
The corresponding spatial eigenfunctions (mode shapes) are $Y_n(x) = B_n \sin(k_n x)$. We can absorb the amplitude $B_n$ into a general amplitude constant for the mode. So, the mode shapes are:
\begin{equation*}
Y_n(x) = \sin\left(\frac{\left(n + \frac{1}{2}\right)\pi}{l} x\right)
\end{equation*}
Combining these, the normal modes of oscillation $y_n(x,t)$ are given by:
\boxed{
\begin{equation*}
y_n(x,t) = C_n \sin\left(\frac{\left(n + \frac{1}{2}\right)\pi}{l} x\right) \cos\left(\frac{\left(n + \frac{1}{2}\right)\pi}{l} \sqrt{\frac{T}{\eta}} t + \phi_n\right), \quad \text{for } n = 0, 1, 2, \dots
\end{equation*}
}
where $C_n$ and $\phi_n$ are arbitrary amplitude and phase constants for each mode, respectively.

